import React from "react";
import styles from "./product.module.css";
import GridLayout from "../layout/grid-layout";
import ProductPresentation from "./product-presentation";
import ProductInfo from "./product-info";
import { useParams } from "react-router-dom";

// Define the interface for product data
interface ProductData {
  id: number;
  name: string;
  price: number;
  img: string;
}

// Your product data
const productData: ProductData[] = [
  {
    id: 0,
    name: "Spiced Mint",
    price: 9.99,
    img: "images/candle-1.svg",
  },
  {
    id: 1,
    name: "Sweet Strawberry",
    price: 9.99,
    img: "images/candle-2.svg",
  },
  // Add more product objects as needed
];

const Product: React.FC = () => {
  const { productId } = useParams<{ productId?: string }>() || {};
  const product: ProductData | undefined = productData.find(
    (product) => product.id === (productId ? parseInt(productId) : NaN)
  );

  if (!product) {
    // Handle the case where the product is not found, for example, display an error message or redirect.
    return <div>Product not found</div>;
  }

  const { img, price, name } = product;

  return (
    <div className={styles.product}>
      <div className="container">
        <GridLayout>
          <div className="left-side">
            <ProductPresentation imgSrc={img} />
          </div>
          <div className={styles.right_side}>
            <ProductInfo name={name} price={price} />
          </div>
        </GridLayout>
      </div>
    </div>
  );
};

export default Product;




